INSERT INTO page_blocks (page_slug, block_type, block_order, content, is_visible) VALUES
('home', 'hero', 0, '{"label":"AMUMA","heading":"A New Way of Traveling","body":"Tourism is changing. Travelers are moving away from crowded destinations and standardized resorts. They are searching for something more rare. Not bigger places — but more meaningful ones. Hidden coastlines. Untouched islands. Villages where hospitality still feels personal. Places where beauty is not manufactured, but discovered.\n\nAMUMA was created to reveal these hidden treasures — a network of intimate retreats designed for explorers who seek beauty, silence, and discovery.","cta":"Join the Founding Circle","cta_target":"#join"}', true),
('home', 'text', 1, '{"heading":"The AMUMA Circle","body":"AMUMA is not simply a collection of hotels. It is a circle of travelers who share a way of exploring the world. Members return to the retreats not only as guests but as part of a living community. They discover new places together, host friends and family, and move across destinations connected by the same spirit of hospitality.\n\nEach retreat becomes both a sanctuary in nature and a meeting point for the community."}', true),
('home', 'text', 2, '{"heading":"Hidden Destinations","body":"AMUMA retreats are created only in places that still feel undiscovered. Not where tourism already dominates. But where nature, culture, and simplicity still define the landscape.\n\nThese are destinations where a small retreat can coexist with the environment while preserving the beauty that makes the place special."}', true),
('home', 'text', 3, '{"heading":"The AMUMA Experience","body":"Experiences include:"}', true),
('home', 'list', 4, '{"items":["Island exploration","Culinary journeys","Boat adventures","Wellness rituals"],"footnote":"Every moment is designed to feel personal and unhurried."}', true),
('home', 'text', 5, '{"heading":"Pebbles","subheading":"Annual experience credits.","body":"Pebbles are annual experience credits. They can be used for:"}', true),
('home', 'list', 6, '{"items":["Accommodation","Dining","Excursions","Boat trips","Spa treatments"],"footnote":"Pebbles renew every year."}', true),
