('home', 'divider', 27, '{}', true),
('home', 'text', 28, '{"heading":"The AMUMA Flywheel","body":"Members join\n→\nRetreats are built\n→\nExperiences generate revenue\n→\nReturns fund expansion\n→\nNew destinations appear","subheading":"This cycle continuously expands the AMUMA ecosystem."}', true),
('home', 'divider', 29, '{}', true),
('home', 'text', 30, '{"heading":"First Chapter: Palawan","body":"The journey begins in Palawan, one of the most extraordinary natural environments in the world. The first retreat will rise along the pristine coastline of San Vicente – Long Beach. The second retreat will follow in Balabac, where AMUMA already owns beachfront land.\n\nPalawan will establish the foundation of the AMUMA ecosystem."}', true),
('home', 'text', 31, '{"heading":"The Retreat","subheading":"San Vicente, Palawan","body":"The San Vicente retreat is intentionally small. This scale ensures space, quiet, and genuine connection with nature."}', true),
