('home', 'list', 49, '{"label":"Founding Circle Benefits","items":["Name on founding plaque at San Vicente Retreat","Early access to future AMUMA retreats","First access to future share offerings","Annual private video update from James","Invitation to annual Founders'' Dinner","Listed as Founding Circle member on website"]}', true),
